import request from '@/utils/request'

// 辅助函数：格式化薪资
const formatSalary = (min, max) => {
  if (!min && !max) return ''
  if (!max) return `${min}K以上`
  if (!min) return `${max}K以下`
  return `${min}K-${max}K`
}

// 辅助函数：格式化城市
const formatCity = (city) => {
  if (!city || !city.length) return ''
  return city.map(c => c.label || c).join('-')
}

// 用户资料相关功能
export const profile = {
  // 获取基本信息
  getBasicInfo: () => {
    return request.get('/api/v1/users/profile/basic/')
  },

  // 更新用户名
  updateUsername: (data) => {
    return request.post('/api/v1/users/account/username/', {
      username: data.username
    })
  },

  // 更新基本信息
  updateBasicInfo: (data) => {
    return request.post('/api/v1/users/profile/basic/', {
      basic_info: data
    })
  },

  // 上传头像
  uploadAvatar: (formData) => {
    return request.post('/api/v1/users/profile/avatar/upload/', formData, {
      headers: {
        'Content-Type': 'multipart/form-data'
      }
    })
  }
}
